import React, { Component } from 'react'
import Image from '../Image';
import "./style.css";
export default class Card extends Component {
  render() {
    const {
      title,
      description,
      imageSrc,
      imageAlt,
      actions
    } = this.props;

    return (
      <div className="card">
        <header>
          <h1>{title}</h1>
        </header>
        <Image src={imageSrc} alt={imageAlt} />
        <section>
          <p>{description}</p>
        </section>
        <footer>
          {actions}
        </footer>
      </div>
    );
  }
}
